// Generate simulated asset health data
const assets = [
  { id: 'PUMP-001', name: 'Primary Coolant Pump', type: 'Pump' },
  { id: 'MOTOR-045', name: 'Conveyor Motor A', type: 'Motor' },
  { id: 'VALVE-112', name: 'Pressure Relief Valve', type: 'Valve' },
  { id: 'COMP-023', name: 'Air Compressor Unit', type: 'Compressor' },
  { id: 'TURB-008', name: 'Steam Turbine Generator', type: 'Turbine' }
];

const healthStatuses = ['Excellent', 'Good', 'Fair', 'Poor', 'Critical'];

const items = assets.map(asset => {
  // Generate random but realistic values
  const degradationScore = Math.random() * 100;
  const temperature = 20 + Math.random() * 80; // 20-100°C
  const vibration = Math.random() * 10; // 0-10 mm/s
  const pressure = 1 + Math.random() * 9; // 1-10 bar
  const operatingHours = Math.floor(Math.random() * 50000);

  // Last maintenance date (random within last 365 days)
  const daysAgo = Math.floor(Math.random() * 365);
  const lastMaintenanceDate = new Date();
  lastMaintenanceDate.setDate(lastMaintenanceDate.getDate() - daysAgo);

  // Determine health status based on degradation score
  let healthStatus;
  if (degradationScore < 20) healthStatus = 'Excellent';
  else if (degradationScore < 40) healthStatus = 'Good';
  else if (degradationScore < 60) healthStatus = 'Fair';
  else if (degradationScore < 80) healthStatus = 'Poor';
  else healthStatus = 'Critical';

  return {
    json: {
      assetId: asset.id,
      assetName: asset.name,
      assetType: asset.type,
      temperature: Math.round(temperature * 100) / 100,
      vibration: Math.round(vibration * 100) / 100,
      pressure: Math.round(pressure * 100) / 100,
      operatingHours: operatingHours,
      lastMaintenanceDate: lastMaintenanceDate.toISOString().split('T')[0],
      degradationScore: Math.round(degradationScore * 100) / 100,
      healthStatus: healthStatus,
      timestamp: new Date().toISOString()
    }
  };
});

return items;

